#[allow(dead_code)]
fn source_assets_from_metadata_blob(
    blob: &[u8],
    uuid: &str,
    file_names: &BTreeSet<&str>,
    rows_by_file_name: &BTreeMap<&str, &ConfigRow>,
    command_refs: &BTreeMap<String, String>,
    metadata_refs: &BTreeMap<String, MetadataCommandReference>,
    object_refs: &BTreeMap<String, String>,
    field_refs: &BTreeMap<String, String>,
    type_index: &BTreeMap<String, String>,
    subsystem_refs: &BTreeMap<String, SubsystemSourceReference>,
) -> Vec<(String, SourceAsset)> {
    metadata_text_row_from_blob(uuid, blob)
        .and_then(|row| {
            source_assets_from_metadata_text_inner(
                &row,
                file_names,
                rows_by_file_name,
                command_refs,
                metadata_refs,
                object_refs,
                field_refs,
                type_index,
                subsystem_refs,
            )
        })
        .unwrap_or_default()
}

fn source_assets_from_metadata_text(
    row: &MetadataTextRow,
    file_names: &BTreeSet<&str>,
    rows_by_file_name: &BTreeMap<&str, &ConfigRow>,
    command_refs: &BTreeMap<String, String>,
    metadata_refs: &BTreeMap<String, MetadataCommandReference>,
    object_refs: &BTreeMap<String, String>,
    field_refs: &BTreeMap<String, String>,
    type_index: &BTreeMap<String, String>,
    subsystem_refs: &BTreeMap<String, SubsystemSourceReference>,
) -> Vec<(String, SourceAsset)> {
    source_assets_from_metadata_text_inner(
        row,
        file_names,
        rows_by_file_name,
        command_refs,
        metadata_refs,
        object_refs,
        field_refs,
        type_index,
        subsystem_refs,
    )
    .unwrap_or_default()
}

fn source_assets_from_metadata_text_inner(
    row: &MetadataTextRow,
    file_names: &BTreeSet<&str>,
    rows_by_file_name: &BTreeMap<&str, &ConfigRow>,
    command_refs: &BTreeMap<String, String>,
    metadata_refs: &BTreeMap<String, MetadataCommandReference>,
    object_refs: &BTreeMap<String, String>,
    field_refs: &BTreeMap<String, String>,
    type_index: &BTreeMap<String, String>,
    subsystem_refs: &BTreeMap<String, SubsystemSourceReference>,
) -> Option<Vec<(String, SourceAsset)>> {
    let uuid = row.file_name.as_str();
    let kind = row.kind.as_deref()?;
    let folder = row.folder?;
    let header = row.header.as_ref()?;
    let object_path = if kind == "Subsystem" {
        subsystem_refs
            .get(uuid)
            .map(|subsystem_ref| subsystem_ref.relative_path.with_extension(""))
            .unwrap_or_else(|| {
                PathBuf::from(folder).join(sanitize_source_path_segment(&header.name))
            })
    } else {
        PathBuf::from(folder).join(sanitize_source_path_segment(&header.name))
    };
    let mut assets = Vec::new();

    if kind == "ExchangePlan" {
        let content_id = format!("{uuid}.1");
        if file_names.contains(content_id.as_str()) {
            assets.push((
                content_id,
                SourceAsset {
                    primary_path: object_path.join("Ext").join("Content.xml"),
                    kind: SourceAssetKind::ExchangePlanContent,
                },
            ));
        }
    }

    if kind == "BusinessProcess" {
        let flowchart_id = format!("{uuid}.7");
        if file_names.contains(flowchart_id.as_str()) {
            assets.push((
                flowchart_id,
                SourceAsset {
                    primary_path: object_path.join("Ext").join("Flowchart.xml"),
                    kind: SourceAssetKind::BusinessProcessFlowchart,
                },
            ));
        }
    }

    if let Some(suffix) = additional_indexes_body_suffix(kind) {
        let additional_indexes_id = format!("{uuid}.{suffix}");
        if file_names.contains(additional_indexes_id.as_str()) {
            assets.push((
                additional_indexes_id,
                SourceAsset {
                    primary_path: object_path.join("Ext").join("AdditionalIndexes.xml"),
                    kind: SourceAssetKind::InflatedBinary,
                },
            ));
        }
    }

    let body_id = format!("{uuid}.0");
    if file_names.contains(body_id.as_str()) {
        let asset = match kind {
            "CommonPicture" => Some(SourceAsset {
                primary_path: object_path.join("Ext").join("Picture.xml"),
                kind: SourceAssetKind::ExtPicture,
            }),
            "ScheduledJob" => Some(SourceAsset {
                primary_path: object_path.join("Ext").join("Schedule.xml"),
                kind: SourceAssetKind::Schedule,
            }),
            "XDTOPackage" => Some(SourceAsset {
                primary_path: object_path.join("Ext").join("Package.bin"),
                kind: SourceAssetKind::InflatedBinary,
            }),
            "Style" => Some(SourceAsset {
                primary_path: object_path.join("Ext").join("Style.xml"),
                kind: SourceAssetKind::StyleBody,
            }),
            "WSReference" => Some(SourceAsset {
                primary_path: object_path.join("Ext").join("WSDefinition.xml"),
                kind: SourceAssetKind::WsDefinition,
            }),
            "Role"
                if rows_by_file_name
                    .get(body_id.as_str())
                    .and_then(|row| decode_hex(&row.binary_hex).ok())
                    .and_then(|bytes| parse_role_rights_blob(&bytes, object_refs, field_refs))
                    .is_some() =>
            {
                Some(SourceAsset {
                    primary_path: object_path.join("Ext").join("Rights.xml"),
                    kind: SourceAssetKind::RoleRights,
                })
            }
            _ => None,
        };
        if let Some(asset) = asset {
            assets.push((body_id, asset));
        }
    }

    let command_mapped_ids = assets
        .iter()
        .map(|(body_id, _)| body_id.clone())
        .collect::<BTreeSet<_>>();
    for suffix in ["0", "1"] {
        let body_id = format!("{uuid}.{suffix}");
        if command_mapped_ids.contains(&body_id) {
            continue;
        }
        if let Some(row) = rows_by_file_name.get(body_id.as_str())
            && let Ok(bytes) = decode_hex(&row.binary_hex)
            && parse_command_interface_blob(&bytes, command_refs, metadata_refs).is_some()
        {
            assets.push((
                body_id,
                SourceAsset {
                    primary_path: object_path.join("Ext").join("CommandInterface.xml"),
                    kind: SourceAssetKind::CommandInterface,
                },
            ));
        }
    }

    let mapped_ids = assets
        .iter()
        .map(|(body_id, _)| body_id.clone())
        .collect::<BTreeSet<_>>();
    let object_row_prefix = format!("{uuid}.");
    let preferred_help_body_id = preferred_help_body_id(kind, uuid);
    for (body_id, body_row) in rows_by_file_name {
        if !body_id.starts_with(&object_row_prefix) || mapped_ids.contains(*body_id) {
            continue;
        }
        if let Ok(help_bytes) = decode_hex(&body_row.binary_hex)
            && parse_help_blob_pages(&help_bytes).is_some()
        {
            if rows_by_file_name.contains_key(preferred_help_body_id.as_str())
                && *body_id != preferred_help_body_id
            {
                continue;
            }
            assets.push((
                (*body_id).to_string(),
                SourceAsset {
                    primary_path: object_path.join("Ext").join("Help.xml"),
                    kind: SourceAssetKind::Help,
                },
            ));
            continue;
        }
        if let Some(xsi_type) = predefined_data_xsi_type(kind)
            && let Ok(predefined_bytes) = decode_hex(&body_row.binary_hex)
            && parse_predefined_data_blob(&predefined_bytes, type_index).is_some()
        {
            assets.push((
                (*body_id).to_string(),
                SourceAsset {
                    primary_path: object_path.join("Ext").join("Predefined.xml"),
                    kind: SourceAssetKind::PredefinedData { xsi_type },
                },
            ));
        }
    }

    Some(assets)
}

fn additional_indexes_body_suffix(kind: &str) -> Option<&'static str> {
    match kind {
        "Document" => Some("3"),
        "AccumulationRegister" => Some("4"),
        _ => None,
    }
}

fn preferred_help_body_id(kind: &str, uuid: &str) -> String {
    let suffix = if matches!(kind, "Form" | "CommonForm") {
        "1"
    } else {
        "5"
    };
    format!("{uuid}.{suffix}")
}

fn write_source_xml_file(
    path: &Path,
    xml: impl AsRef<[u8]>,
    source_version: InfobaseConfigSourceVersion,
) -> Result<()> {
    let normalized = normalize_source_xml_version_bytes(xml.as_ref(), source_version);
    fs::write(path, normalized).with_context(|| format!("failed to write {}", path.display()))
}

fn is_xml_path(path: &Path) -> bool {
    path.extension().and_then(|ext| ext.to_str()) == Some("xml")
}

const DCS_SCHEMA_NS: &[u8] = b"http://v8.1c.ru/8.1/data-composition-system/schema";
const DCS_COMMON_NS: &[u8] = b"http://v8.1c.ru/8.1/data-composition-system/common";
const DCS_CORE_NS: &[u8] = b"http://v8.1c.ru/8.1/data-composition-system/core";
const DCS_SETTINGS_NS: &[u8] = b"http://v8.1c.ru/8.1/data-composition-system/settings";
const DATA_CORE_NS: &[u8] = b"http://v8.1c.ru/8.1/data/core";
const DATA_UI_NS: &[u8] = b"http://v8.1c.ru/8.1/data/ui";
const STYLE_NS: &[u8] = b"http://v8.1c.ru/8.1/data/ui/style";
const SYS_NS: &[u8] = b"http://v8.1c.ru/8.1/data/ui/fonts/system";
const WEB_NS: &[u8] = b"http://v8.1c.ru/8.1/data/ui/colors/web";
const WIN_NS: &[u8] = b"http://v8.1c.ru/8.1/data/ui/colors/windows";
const XSI_NS: &[u8] = b"http://www.w3.org/2001/XMLSchema-instance";
const XS_NS: &[u8] = b"http://www.w3.org/2001/XMLSchema";
const DCS_SETTINGS_URI: &str = "http://v8.1c.ru/8.1/data-composition-system/settings";

fn normalize_data_composition_schema_template_xml(
    inflated: &[u8],
    type_index: &BTreeMap<String, String>,
) -> Option<Vec<u8>> {
    let xml_start = find_bytes(inflated, b"<?xml")?;
    let text = std::str::from_utf8(&inflated[xml_start..]).ok()?;
    let documents = split_embedded_xml_documents(text);
    let schema_doc = documents.iter().find(|document| {
        document.contains("<SchemaFile") && document.contains("dataCompositionSchema")
    })?;
    let mut xml = canonicalize_data_composition_schema_document(schema_doc)?;
    rewrite_data_composition_type_ids(&mut xml, type_index);
    if let Some(settings_doc) = documents
        .iter()
        .find(|document| document.contains("<Settings") && document.contains(DCS_SETTINGS_URI))
        && let Some(settings) = canonicalize_data_composition_settings_document(settings_doc)
    {
        insert_data_composition_settings(&mut xml, &settings);
    }
    Some(xml.into_bytes())
}

fn rewrite_data_composition_type_ids(xml: &mut String, type_index: &BTreeMap<String, String>) {
    const OPEN: &str = "<v8:TypeId>";
    const CLOSE: &str = "</v8:TypeId>";
    const ANY_IB_REF_TYPE_ID: &str = "280f5f0e-9c8a-49cc-bf6d-4d296cc17a63";
    const CFG_PREFIX: &str = "cfg:";
    const CURRENT_CONFIG_NS: &str = "http://v8.1c.ru/8.1/data/enterprise/current-config";

    let mut rewritten = String::with_capacity(xml.len());
    let mut cursor = 0usize;
    while let Some(relative_start) = xml[cursor..].find(OPEN) {
        let start = cursor + relative_start;
        let value_start = start + OPEN.len();
        let Some(relative_end) = xml[value_start..].find(CLOSE) else {
            break;
        };
        let value_end = value_start + relative_end;
        let type_id = xml[value_start..value_end].trim();
        let dcs_cfg_prefix = data_composition_current_config_prefix(xml, start);
        let replacement = if type_id.eq_ignore_ascii_case(ANY_IB_REF_TYPE_ID) {
            Some(format!(
                "<v8:TypeSet xmlns:{dcs_cfg_prefix}=\"{CURRENT_CONFIG_NS}\">{dcs_cfg_prefix}:AnyIBRef</v8:TypeSet>"
            ))
        } else {
            type_index
                .get(type_id)
                .and_then(|reference| reference.strip_prefix(CFG_PREFIX))
                .map(|reference| {
                    format!(
                        "<v8:Type xmlns:{dcs_cfg_prefix}=\"{CURRENT_CONFIG_NS}\">{dcs_cfg_prefix}:{}</v8:Type>",
                        escape_xml_text(reference)
                    )
                })
        };
        if let Some(replacement) = replacement {
            rewritten.push_str(&xml[cursor..start]);
            rewritten.push_str(&replacement);
            cursor = value_end + CLOSE.len();
        } else {
            rewritten.push_str(&xml[cursor..value_end + CLOSE.len()]);
            cursor = value_end + CLOSE.len();
        }
    }
    if cursor == 0 {
        return;
    }
    rewritten.push_str(&xml[cursor..]);
    *xml = rewritten;
}

#[derive(Debug)]
struct DcsXmlStackEntry<'a> {
    name: &'a str,
    xsi_type: Option<&'a str>,
}

fn data_composition_current_config_prefix(xml: &str, position: usize) -> &'static str {
    let mut stack = Vec::<DcsXmlStackEntry<'_>>::new();
    let mut cursor = 0usize;
    let bytes = xml.as_bytes();
    let limit = position.min(xml.len());
    while cursor < limit {
        let Some(relative_start) = xml[cursor..limit].find('<') else {
            break;
        };
        let start = cursor + relative_start;
        if xml[start..].starts_with("<!--") {
            let Some(relative_end) = xml[start + 4..limit].find("-->") else {
                break;
            };
            cursor = start + 4 + relative_end + 3;
            continue;
        }
        if xml[start..].starts_with("<![CDATA[") {
            let Some(relative_end) = xml[start + 9..limit].find("]]>") else {
                break;
            };
            cursor = start + 9 + relative_end + 3;
            continue;
        }
        let Some(end) = find_xml_tag_end(bytes, start + 1, limit) else {
            break;
        };
        let tag = xml[start + 1..end].trim();
        if tag.starts_with('?') || tag.starts_with('!') {
            cursor = end + 1;
            continue;
        }
        if let Some(end_name) = tag.strip_prefix('/') {
            let end_name = dcs_xml_tag_name(end_name);
            if let Some(index) = stack.iter().rposition(|entry| entry.name == end_name) {
                stack.truncate(index);
            }
        } else {
            let self_closing = tag.ends_with('/');
            let tag = tag.strip_suffix('/').unwrap_or(tag).trim_end();
            let name = dcs_xml_tag_name(tag);
            if !self_closing && !name.is_empty() {
                stack.push(DcsXmlStackEntry {
                    name,
                    xsi_type: dcs_xml_attribute_value(tag, "xsi:type"),
                });
            }
        }
        cursor = end + 1;
    }

    if stack.iter().any(|entry| entry.name == "parameter") {
        "d4p1"
    } else if stack
        .iter()
        .any(|entry| entry.name == "item" && entry.xsi_type == Some("DataSetObject"))
    {
        "d6p1"
    } else {
        "d5p1"
    }
}

fn find_xml_tag_end(bytes: &[u8], mut cursor: usize, limit: usize) -> Option<usize> {
    let mut quote = None::<u8>;
    while cursor < limit {
        let byte = bytes[cursor];
        if quote == Some(byte) {
            quote = None;
        } else if quote.is_none() && matches!(byte, b'"' | b'\'') {
            quote = Some(byte);
        } else if quote.is_none() && byte == b'>' {
            return Some(cursor);
        }
        cursor += 1;
    }
    None
}

fn dcs_xml_tag_name(tag: &str) -> &str {
    tag.split_whitespace().next().unwrap_or("")
}

fn dcs_xml_attribute_value<'a>(tag: &'a str, name: &str) -> Option<&'a str> {
    let mut rest = tag;
    loop {
        let index = rest.find(name)?;
        let candidate = &rest[index + name.len()..];
        let before_is_name_char = index > 0 && rest.as_bytes()[index - 1].is_ascii_alphanumeric()
            || index > 0 && matches!(rest.as_bytes()[index - 1], b':' | b'_' | b'-');
        if before_is_name_char || !candidate.trim_start().starts_with('=') {
            rest = &candidate[1.min(candidate.len())..];
            continue;
        }
        let after_equals = candidate.trim_start().strip_prefix('=')?.trim_start();
        let quote = after_equals.as_bytes().first().copied()?;
        if !matches!(quote, b'"' | b'\'') {
            return None;
        }
        let value_start = 1;
        let value_end = after_equals[value_start..].find(quote as char)? + value_start;
        return Some(&after_equals[value_start..value_end]);
    }
}

fn extract_ws_definition_xml(inflated: &[u8]) -> Option<Vec<u8>> {
    let xml_start = find_bytes(inflated, b"<?xml")?;
    let xml = &inflated[xml_start..];
    let mut content = Vec::with_capacity(3 + xml.len());
    content.extend_from_slice(b"\xEF\xBB\xBF");
    content.extend_from_slice(xml);
    Some(content)
}

fn find_bytes(haystack: &[u8], needle: &[u8]) -> Option<usize> {
    haystack
        .windows(needle.len())
        .position(|window| window == needle)
}

fn split_embedded_xml_documents(text: &str) -> Vec<&str> {
    let mut starts = Vec::new();
    let mut cursor = 0;
    while let Some(offset) = text[cursor..].find("<?xml") {
        starts.push(cursor + offset);
        cursor += offset + "<?xml".len();
    }
    starts
        .iter()
        .enumerate()
        .map(|(index, start)| {
            let end = starts.get(index + 1).copied().unwrap_or(text.len());
            text[*start..end].trim_matches('\u{feff}').trim()
        })
        .filter(|document| !document.is_empty())
        .collect()
}

fn canonicalize_data_composition_schema_document(document: &str) -> Option<String> {
    let mut writer = DataCompositionXmlWriter::new();
    writer.fixed_decl_and_schema_root();
    let root_len = writer.output.len();
    writer.write_document(document, DataCompositionDocumentMode::Schema)?;
    let body = writer.output[root_len..].to_string();
    writer.output.truncate(root_len);
    writer
        .output
        .push_str(&normalize_data_composition_schema_body_indent(&body));
    writer.output.push_str("\r\n</DataCompositionSchema>");
    Some(writer.output)
}

fn canonicalize_data_composition_settings_document(document: &str) -> Option<String> {
    let mut writer = DataCompositionXmlWriter::new();
    writer.write_document(document, DataCompositionDocumentMode::Settings)?;
    let settings = writer
        .output
        .trim_start_matches(['\r', '\n', '\t'])
        .to_string();
    Some(indent_data_composition_settings(&settings))
}

fn insert_data_composition_settings(xml: &mut String, settings: &str) {
    let marker = "\r\n\t</settingsVariant>";
    if let Some(index) = xml.find(marker) {
        xml.insert_str(index, settings);
        return;
    }
    let root_marker = "\r\n</DataCompositionSchema>";
    if let Some(index) = xml.find(root_marker) {
        xml.insert_str(index, settings);
    }
}

fn normalize_data_composition_schema_body_indent(body: &str) -> String {
    let body = body.strip_prefix("\r\n\r\n").unwrap_or(body);
    body.trim_end_matches(['\r', '\n', '\t']).to_string()
}

fn deindent_lines_by_one_tab(text: &str) -> String {
    text.split_inclusive('\n')
        .map(|line| line.strip_prefix('\t').unwrap_or(line))
        .collect()
}

fn is_xml_whitespace(text: &str) -> bool {
    text.bytes()
        .all(|byte| matches!(byte, b'\r' | b'\n' | b'\t' | b' '))
}

fn indent_data_composition_settings(settings: &str) -> String {
    let mut indented = String::from("\r\n");
    for line in settings.split_inclusive('\n') {
        indented.push_str("\t\t");
        indented.push_str(line);
    }
    indented
}

enum DataCompositionDocumentMode {
    Schema,
    Settings,
}

struct DataCompositionXmlWriter {
    output: String,
    skip_depth: usize,
}

impl DataCompositionXmlWriter {
    fn new() -> Self {
        Self {
            output: String::new(),
            skip_depth: 0,
        }
    }

    fn fixed_decl_and_schema_root(&mut self) {
        self.output.push_str(
            "\u{feff}<?xml version=\"1.0\" encoding=\"UTF-8\"?>\r\n\
<DataCompositionSchema xmlns=\"http://v8.1c.ru/8.1/data-composition-system/schema\" xmlns:dcscom=\"http://v8.1c.ru/8.1/data-composition-system/common\" xmlns:dcscor=\"http://v8.1c.ru/8.1/data-composition-system/core\" xmlns:dcsset=\"http://v8.1c.ru/8.1/data-composition-system/settings\" xmlns:v8=\"http://v8.1c.ru/8.1/data/core\" xmlns:v8ui=\"http://v8.1c.ru/8.1/data/ui\" xmlns:xs=\"http://www.w3.org/2001/XMLSchema\" xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\">",
        );
    }

    fn write_document(&mut self, document: &str, mode: DataCompositionDocumentMode) -> Option<()> {
        let mut reader = NsReader::from_str(document);
        reader.config_mut().trim_text(false);
        loop {
            match reader.read_event().ok()? {
                Event::Start(event) => {
                    let (namespace, local) = reader.resolve_element(event.name());
                    let local = local.as_ref();
                    if self.should_skip(namespace_ref(&namespace), local, &mode) {
                        continue;
                    }
                    if self.skip_depth == 0 {
                        self.write_start_tag(
                            &reader,
                            &event,
                            namespace_ref(&namespace),
                            local,
                            false,
                            &mode,
                        )?;
                    }
                }
                Event::Empty(event) => {
                    if self.skip_depth == 0 {
                        let (namespace, local) = reader.resolve_element(event.name());
                        self.write_start_tag(
                            &reader,
                            &event,
                            namespace_ref(&namespace),
                            local.as_ref(),
                            true,
                            &mode,
                        )?;
                    }
                }
                Event::End(event) => {
                    let (namespace, local) = reader.resolve_element(event.name());
                    let local = local.as_ref();
                    if self.should_skip(namespace_ref(&namespace), local, &mode) {
                        continue;
                    }
                    if matches!(mode, DataCompositionDocumentMode::Schema)
                        && namespace_ref(&namespace) == Some(DCS_SCHEMA_NS)
                        && local == b"dataCompositionSchema"
                    {
                        continue;
                    }
                    let name = if matches!(mode, DataCompositionDocumentMode::Settings)
                        && namespace_ref(&namespace) == Some(DCS_SETTINGS_NS)
                        && local == b"Settings"
                    {
                        "dcsset:settings".to_string()
                    } else {
                        canonical_data_composition_name(namespace_ref(&namespace), local)?
                    };
                    self.output.push_str("</");
                    self.output.push_str(&name);
                    self.output.push('>');
                }
                Event::Text(event) => {
                    if self.skip_depth == 0 {
                        let text = std::str::from_utf8(event.as_ref()).ok()?;
                        if matches!(mode, DataCompositionDocumentMode::Schema)
                            && is_xml_whitespace(text)
                        {
                            self.output.push_str(&deindent_lines_by_one_tab(text));
                        } else {
                            self.output.push_str(text);
                        }
                    }
                }
                Event::CData(event) => {
                    if self.skip_depth == 0 {
                        self.output.push_str("<![CDATA[");
                        self.output
                            .push_str(std::str::from_utf8(event.as_ref()).ok()?);
                        self.output.push_str("]]>");
                    }
                }
                Event::Comment(event) => {
                    if self.skip_depth == 0 {
                        self.output.push_str("<!--");
                        self.output
                            .push_str(std::str::from_utf8(event.as_ref()).ok()?);
                        self.output.push_str("-->");
                    }
                }
                Event::GeneralRef(event) => {
                    if self.skip_depth == 0 {
                        self.output.push('&');
                        self.output
                            .push_str(std::str::from_utf8(event.as_ref()).ok()?);
                        self.output.push(';');
                    }
                }
                Event::Decl(_) => {}
                Event::Eof => break,
                _ => {}
            }
        }
        Some(())
    }

    fn should_skip(
        &self,
        namespace: Option<&[u8]>,
        local: &[u8],
        mode: &DataCompositionDocumentMode,
    ) -> bool {
        matches!(mode, DataCompositionDocumentMode::Schema)
            && namespace.is_none()
            && local == b"SchemaFile"
    }

    fn write_start_tag(
        &mut self,
        reader: &NsReader<&[u8]>,
        event: &quick_xml::events::BytesStart<'_>,
        namespace: Option<&[u8]>,
        local: &[u8],
        empty: bool,
        mode: &DataCompositionDocumentMode,
    ) -> Option<()> {
        if matches!(mode, DataCompositionDocumentMode::Schema)
            && namespace == Some(DCS_SCHEMA_NS)
            && local == b"dataCompositionSchema"
        {
            return Some(());
        }
        let is_settings_root = matches!(mode, DataCompositionDocumentMode::Settings)
            && namespace == Some(DCS_SETTINGS_NS)
            && local == b"Settings";
        let name = if is_settings_root {
            "dcsset:settings".to_string()
        } else {
            canonical_data_composition_name(namespace, local)?
        };
        self.output.push('<');
        self.output.push_str(&name);
        if is_settings_root {
            self.output.push_str(
                " xmlns:style=\"http://v8.1c.ru/8.1/data/ui/style\" xmlns:sys=\"http://v8.1c.ru/8.1/data/ui/fonts/system\" xmlns:web=\"http://v8.1c.ru/8.1/data/ui/colors/web\" xmlns:win=\"http://v8.1c.ru/8.1/data/ui/colors/windows\"",
            );
        }
        for attribute in event.attributes().with_checks(false) {
            let attribute = attribute.ok()?;
            if is_xmlns_attribute(attribute.key.as_ref()) {
                continue;
            }
            let (attr_namespace, attr_local) = reader.resolve_attribute(attribute.key);
            let attr_name = canonical_data_composition_attr_name(
                namespace_ref(&attr_namespace),
                attr_local.as_ref(),
            )?;
            let value = attribute
                .decode_and_unescape_value(reader.decoder())
                .ok()?
                .into_owned();
            let value = canonical_data_composition_attr_value(&attr_name, &value, namespace);
            self.output.push(' ');
            self.output.push_str(&attr_name);
            self.output.push_str("=\"");
            self.output.push_str(&escape_xml_text(&value));
            self.output.push('"');
        }
        if empty {
            self.output.push_str("/>");
        } else {
            self.output.push('>');
        }
        Some(())
    }
}

fn namespace_ref<'a>(namespace: &'a ResolveResult<'a>) -> Option<&'a [u8]> {
    match namespace {
        ResolveResult::Bound(namespace) => Some(namespace.0),
        _ => None,
    }
}

fn is_xmlns_attribute(name: &[u8]) -> bool {
    name == b"xmlns" || name.starts_with(b"xmlns:")
}

fn canonical_data_composition_name(namespace: Option<&[u8]>, local: &[u8]) -> Option<String> {
    let local = std::str::from_utf8(local).ok()?;
    match namespace {
        Some(DCS_SCHEMA_NS) => Some(local.to_string()),
        Some(DCS_COMMON_NS) => Some(format!("dcscom:{local}")),
        Some(DCS_CORE_NS) => Some(format!("dcscor:{local}")),
        Some(DCS_SETTINGS_NS) => Some(format!("dcsset:{local}")),
        Some(DATA_CORE_NS) => Some(format!("v8:{local}")),
        Some(DATA_UI_NS) => Some(format!("v8ui:{local}")),
        Some(STYLE_NS) => Some(format!("style:{local}")),
        Some(SYS_NS) => Some(format!("sys:{local}")),
        Some(WEB_NS) => Some(format!("web:{local}")),
        Some(WIN_NS) => Some(format!("win:{local}")),
        Some(XSI_NS) => Some(format!("xsi:{local}")),
        Some(XS_NS) => Some(format!("xs:{local}")),
        Some(_) | None => Some(local.to_string()),
    }
}

fn canonical_data_composition_attr_name(namespace: Option<&[u8]>, local: &[u8]) -> Option<String> {
    let local = std::str::from_utf8(local).ok()?;
    match namespace {
        Some(XSI_NS) => Some(format!("xsi:{local}")),
        Some(XS_NS) => Some(format!("xs:{local}")),
        Some(DATA_CORE_NS) => Some(format!("v8:{local}")),
        Some(DATA_UI_NS) => Some(format!("v8ui:{local}")),
        Some(DCS_CORE_NS) => Some(format!("dcscor:{local}")),
        Some(DCS_SETTINGS_NS) => Some(format!("dcsset:{local}")),
        Some(DCS_COMMON_NS) => Some(format!("dcscom:{local}")),
        Some(_) | None => Some(local.to_string()),
    }
}

fn canonical_data_composition_attr_value(
    attr_name: &str,
    value: &str,
    element_namespace: Option<&[u8]>,
) -> String {
    if attr_name != "xsi:type" {
        return value.to_string();
    }
    let suffix = value
        .rsplit_once(':')
        .map(|(_, suffix)| suffix)
        .unwrap_or(value);
    match suffix {
        "LocalStringType" => "v8:LocalStringType".to_string(),
        "Field" => "dcscor:Field".to_string(),
        _ if is_dcs_settings_xsi_type(suffix) => format!("dcsset:{suffix}"),
        _ if element_namespace == Some(DCS_SETTINGS_NS) && !value.contains(':') => {
            format!("dcsset:{value}")
        }
        _ => value.to_string(),
    }
}

fn is_dcs_settings_xsi_type(value: &str) -> bool {
    matches!(
        value,
        "DataCompositionAttributesPlacement"
            | "DataCompositionChartLegendPlacement"
            | "DataCompositionFixation"
            | "DataCompositionGroupFieldsPlacement"
            | "DataCompositionGroupPlacement"
            | "DataCompositionGroupTemplateType"
            | "DataCompositionGroupUseVariant"
            | "DataCompositionPictureOutputType"
            | "DataCompositionResourcesAutoPosition"
            | "DataCompositionResourcesPlacement"
            | "DataCompositionTextOutputType"
            | "FilterItemComparison"
            | "FilterItemGroup"
            | "GroupItemAuto"
            | "GroupItemField"
            | "OrderItemAuto"
            | "OrderItemField"
            | "SelectedItemAuto"
            | "SelectedItemField"
            | "SelectedItemFolder"
            | "SettingsParameterValue"
            | "StructureItemChart"
            | "StructureItemGroup"
            | "StructureItemNestedObject"
            | "StructureItemTable"
            | "UserFieldCase"
            | "UserFieldExpression"
    )
}

fn write_source_asset(
    context: &DumpRowContext<'_>,
    asset: &SourceAsset,
    bytes: &[u8],
    parsed_form_body: Option<&ParsedFormBodyBlob>,
    timings: &mut MssqlDumpTimingReport,
) -> Result<PathBuf> {
    let output_dir = context.output_dir;
    match &asset.kind {
        SourceAssetKind::ExtPicture => {
            let picture = extract_ext_picture(bytes).with_context(|| {
                format!(
                    "failed to extract picture from source asset {}",
                    asset.primary_path.display()
                )
            })?;
            let xml_path = output_dir.join(&asset.primary_path);
            if let Some(parent) = xml_path.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }

            let picture_dir = output_dir.join(asset.primary_path.with_extension(""));
            fs::create_dir_all(&picture_dir)
                .with_context(|| format!("failed to create {}", picture_dir.display()))?;
            let picture_file_name = ext_picture_file_name(&picture.content);
            let picture_path = picture_dir.join(picture_file_name);
            fs::write(&picture_path, &picture.content)
                .with_context(|| format!("failed to write {}", picture_path.display()))?;
            write_source_xml_file(
                &xml_path,
                format_ext_picture_xml(
                    picture_file_name,
                    picture.transparent_pixel,
                    context.source_version,
                ),
                context.source_version,
            )?;
        }
        SourceAssetKind::Schedule => {
            let xml = extract_schedule_xml(bytes).with_context(|| {
                format!(
                    "failed to extract schedule from source asset {}",
                    asset.primary_path.display()
                )
            })?;
            let path = output_dir.join(&asset.primary_path);
            if let Some(parent) = path.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }
            write_source_xml_file(&path, xml, context.source_version)?;
        }
        SourceAssetKind::StandaloneContent => {
            let xml = extract_standalone_content_xml(bytes, context.standalone_refs).with_context(
                || {
                    format!(
                        "failed to extract standalone content from source asset {}",
                        asset.primary_path.display()
                    )
                },
            )?;
            let path = output_dir.join(&asset.primary_path);
            if let Some(parent) = path.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }
            write_source_xml_file(&path, xml, context.source_version)?;
        }
        SourceAssetKind::StyleBody => {
            let xml = extract_style_body_xml(bytes, context.object_refs).with_context(|| {
                format!(
                    "failed to extract style body from source asset {}",
                    asset.primary_path.display()
                )
            })?;
            let path = output_dir.join(&asset.primary_path);
            if let Some(parent) = path.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }
            write_source_xml_file(&path, xml, context.source_version)?;
        }
        SourceAssetKind::Form => {
            let form_xml_started = Instant::now();
            let owned_body;
            let body = if let Some(body) = parsed_form_body {
                body
            } else {
                owned_body = parse_form_body_blob(bytes).with_context(|| {
                    format!(
                        "failed to parse form body from source asset {}",
                        asset.primary_path.display()
                    )
                })?;
                &owned_body
            };
            let xml =
                extract_form_body_xml_from_body_timed(body, context.object_refs, Some(timings))
                    .with_context(|| {
                        format!(
                            "failed to extract form xml from source asset {}",
                            asset.primary_path.display()
                        )
                    })?;
            let path = output_dir.join(&asset.primary_path);
            if let Some(parent) = path.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }
            write_source_xml_file(&path, xml, context.source_version)?;
            timings.source_asset_form_xml_cpu_ms += elapsed_ms(form_xml_started);

            let form_items_started = Instant::now();
            for item_asset in extract_form_item_assets(bytes) {
                let item_path = output_dir
                    .join(asset.primary_path.with_extension(""))
                    .join("Items")
                    .join(sanitize_source_path_segment(&item_asset.item_name))
                    .join(&item_asset.file_name);
                if let Some(parent) = item_path.parent() {
                    fs::create_dir_all(parent)
                        .with_context(|| format!("failed to create {}", parent.display()))?;
                }
                fs::write(&item_path, &item_asset.content)
                    .with_context(|| format!("failed to write {}", item_path.display()))?;
            }
            timings.source_asset_form_items_cpu_ms += elapsed_ms(form_items_started);
        }
        SourceAssetKind::Help => {
            let help = parse_help_blob(bytes).with_context(|| {
                format!(
                    "failed to extract help from source asset {}",
                    asset.primary_path.display()
                )
            })?;
            let xml_path = output_dir.join(&asset.primary_path);
            if let Some(parent) = xml_path.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }

            let help_dir = output_dir.join(asset.primary_path.with_extension(""));
            fs::create_dir_all(&help_dir)
                .with_context(|| format!("failed to create {}", help_dir.display()))?;
            for page in &help.pages {
                let page_path = help_dir.join(&page.file_name);
                fs::write(
                    &page_path,
                    rewrite_help_links(&page.content, context.help_refs),
                )
                .with_context(|| format!("failed to write {}", page_path.display()))?;
            }
            if !help.files.is_empty() {
                let files_dir = help_dir.join("_files");
                fs::create_dir_all(&files_dir)
                    .with_context(|| format!("failed to create {}", files_dir.display()))?;
                for file in &help.files {
                    let file_path = files_dir.join(&file.file_name);
                    fs::write(&file_path, &file.content)
                        .with_context(|| format!("failed to write {}", file_path.display()))?;
                }
            }
            write_source_xml_file(
                &xml_path,
                format_help_xml(&help.pages),
                context.source_version,
            )?;
        }
        SourceAssetKind::DataCompositionSchema => {
            let inflated = inflate_raw_deflate(bytes).with_context(|| {
                format!(
                    "failed to inflate source asset {}",
                    asset.primary_path.display()
                )
            })?;
            let content =
                normalize_data_composition_schema_template_xml(&inflated, context.type_index)
                    .unwrap_or(inflated);
            let path = output_dir.join(&asset.primary_path);
            if let Some(parent) = path.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }
            write_source_xml_file(&path, content, context.source_version)?;
        }
        SourceAssetKind::WsDefinition => {
            let inflated = inflate_raw_deflate(bytes).with_context(|| {
                format!(
                    "failed to inflate source asset {}",
                    asset.primary_path.display()
                )
            })?;
            let content = extract_ws_definition_xml(&inflated).unwrap_or(inflated);
            let path = output_dir.join(&asset.primary_path);
            if let Some(parent) = path.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }
            write_source_xml_file(&path, content, context.source_version)?;
        }
        SourceAssetKind::HomePageWorkArea => {
            let work_area =
                parse_home_page_work_area_blob(bytes, context.form_refs).with_context(|| {
                    format!(
                        "failed to extract home page work area from source asset {}",
                        asset.primary_path.display()
                    )
                })?;
            let path = output_dir.join(&asset.primary_path);
            if let Some(parent) = path.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }
            write_source_xml_file(
                &path,
                format_home_page_work_area_xml(&work_area, context.source_version),
                context.source_version,
            )?;
        }
        SourceAssetKind::ClientApplicationInterface => {
            let interface = parse_client_application_interface_blob(bytes).with_context(|| {
                format!(
                    "failed to extract client application interface from source asset {}",
                    asset.primary_path.display()
                )
            })?;
            let path = output_dir.join(&asset.primary_path);
            if let Some(parent) = path.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }
            write_source_xml_file(
                &path,
                format_client_application_interface_xml(&interface),
                context.source_version,
            )?;
        }
        SourceAssetKind::InflatedBinary => {
            let inflated = inflate_raw_deflate(bytes).with_context(|| {
                format!(
                    "failed to inflate source asset {}",
                    asset.primary_path.display()
                )
            })?;
            let path = output_dir.join(&asset.primary_path);
            if let Some(parent) = path.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }
            if is_xml_path(&asset.primary_path) {
                write_source_xml_file(&path, inflated, context.source_version)?;
            } else {
                fs::write(&path, inflated)
                    .with_context(|| format!("failed to write {}", path.display()))?;
            }
        }
        SourceAssetKind::InflatedBase64OrBinary => {
            let inflated = inflate_raw_deflate(bytes).with_context(|| {
                format!(
                    "failed to inflate source asset {}",
                    asset.primary_path.display()
                )
            })?;
            let content = if let Ok(text) = std::str::from_utf8(&inflated) {
                extract_base64_payload(text)
                    .and_then(decode_base64_mime)
                    .unwrap_or(inflated)
            } else {
                inflated
            };
            let path = output_dir.join(&asset.primary_path);
            if let Some(parent) = path.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }
            if is_xml_path(&asset.primary_path) {
                write_source_xml_file(&path, content, context.source_version)?;
            } else {
                fs::write(&path, content)
                    .with_context(|| format!("failed to write {}", path.display()))?;
            }
        }
        SourceAssetKind::PredefinedData { xsi_type } => {
            let items =
                parse_predefined_data_blob(bytes, context.type_index).with_context(|| {
                    format!(
                        "failed to extract predefined data from source asset {}",
                        asset.primary_path.display()
                    )
                })?;
            let path = output_dir.join(&asset.primary_path);
            if let Some(parent) = path.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }
            write_source_xml_file(
                &path,
                format_predefined_data_xml(xsi_type, &items),
                context.source_version,
            )?;
        }
        SourceAssetKind::RoleRights => {
            let rights = parse_role_rights_blob(bytes, context.object_refs, context.field_refs)
                .with_context(|| {
                    format!(
                        "failed to extract role rights from source asset {}",
                        asset.primary_path.display()
                    )
                })?;
            let path = output_dir.join(&asset.primary_path);
            if let Some(parent) = path.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }
            write_source_xml_file(
                &path,
                format_role_rights_xml(&rights),
                context.source_version,
            )?;
        }
        SourceAssetKind::CommandInterface => {
            let entries =
                parse_command_interface_blob(bytes, context.command_refs, context.metadata_refs)
                    .with_context(|| {
                        format!(
                            "failed to extract command interface from source asset {}",
                            asset.primary_path.display()
                        )
                    })?;
            let path = output_dir.join(&asset.primary_path);
            if let Some(parent) = path.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }
            write_source_xml_file(
                &path,
                format_command_interface_xml(&entries),
                context.source_version,
            )?;
        }
        SourceAssetKind::ExchangePlanContent => {
            let items =
                parse_exchange_plan_content_blob(bytes, context.object_refs, context.type_index)
                    .with_context(|| {
                        format!(
                            "failed to extract exchange plan content from source asset {}",
                            asset.primary_path.display()
                        )
                    })?;
            let path = output_dir.join(&asset.primary_path);
            if let Some(parent) = path.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }
            write_source_xml_file(
                &path,
                format_exchange_plan_content_xml(&items),
                context.source_version,
            )?;
        }
        SourceAssetKind::BusinessProcessFlowchart => {
            let flowchart = parse_business_process_flowchart_blob(bytes).with_context(|| {
                format!(
                    "failed to extract business process flowchart from source asset {}",
                    asset.primary_path.display()
                )
            })?;
            let path = output_dir.join(&asset.primary_path);
            if let Some(parent) = path.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }
            write_source_xml_file(
                &path,
                format_business_process_flowchart_xml(&flowchart),
                context.source_version,
            )?;
        }
        SourceAssetKind::MoxelSpreadsheet => {
            let xml =
                extract_moxel_spreadsheet_xml(bytes, context.object_refs).with_context(|| {
                    format!(
                        "failed to extract spreadsheet template from source asset {}",
                        asset.primary_path.display()
                    )
                })?;
            let path = output_dir.join(&asset.primary_path);
            if let Some(parent) = path.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }
            write_source_xml_file(&path, xml, context.source_version)?;
        }
    }

    Ok(asset.primary_path.clone())
}

