fn parse_form_table_property_bag_bool(fields: &[&str], key: &str) -> Option<bool> {
    let value = form_table_property_bag_value(fields, key)?;
    let fields = split_1c_braced_fields(value.trim(), 0)?;
    if fields.first().and_then(|field| parse_1c_string(field))? != "B" {
        return None;
    }
    match fields.get(1).map(|field| field.trim())? {
        "0" => Some(false),
        "1" => Some(true),
        _ => None,
    }
}

fn parse_form_table_property_bag_number(fields: &[&str], key: &str) -> Option<String> {
    let value = form_table_property_bag_value(fields, key)?;
    let fields = split_1c_braced_fields(value.trim(), 0)?;
    if fields.first().and_then(|field| parse_1c_string(field))? != "N" {
        return None;
    }
    fields
        .get(1)
        .map(|field| field.trim().to_string())
        .filter(|value| value.parse::<u32>().is_ok())
}

fn parse_form_table_property_bag_string(fields: &[&str], key: &str) -> Option<String> {
    let value = form_table_property_bag_value(fields, key)?;
    let fields = split_1c_braced_fields(value.trim(), 0)?;
    if fields.first().and_then(|field| parse_1c_string(field))? != "S" {
        return None;
    }
    fields.get(1).and_then(|field| parse_1c_string(field))
}

fn resolve_form_child_item_user_settings_groups(items: &mut [FormChildItem], fields: &[&str]) {
    let mut item_names_by_id = BTreeMap::<String, String>::new();
    for field in fields {
        collect_form_child_item_names_by_id(field, &mut item_names_by_id);
    }
    let mut group_names_by_table_id = BTreeMap::<String, String>::new();
    for field in fields {
        collect_form_table_user_settings_groups(
            field,
            &item_names_by_id,
            &mut group_names_by_table_id,
        );
    }
    apply_form_table_user_settings_groups(items, &group_names_by_table_id);
}

fn collect_form_child_item_names_by_id(
    field: &str,
    item_names_by_id: &mut BTreeMap<String, String>,
) {
    let Some(fields) = split_1c_braced_fields(field.trim(), 0) else {
        return;
    };
    if let Some(wrapper) = fields.first().map(|field| field.trim())
        && form_child_item_tag(wrapper, &fields).is_some()
        && let Some(identity) = fields
            .get(1)
            .and_then(|field| split_1c_braced_fields(field.trim(), 0))
        && let Some(id) = identity.first().map(|field| field.trim())
        && id != "0"
        && let Some(name) = parse_form_child_item_name(wrapper, &fields)
    {
        item_names_by_id.insert(id.to_string(), name);
    }
    for nested in fields {
        if nested.trim_start().starts_with('{') {
            collect_form_child_item_names_by_id(nested, item_names_by_id);
        }
    }
}

fn collect_form_table_user_settings_groups(
    field: &str,
    item_names_by_id: &BTreeMap<String, String>,
    group_names_by_table_id: &mut BTreeMap<String, String>,
) {
    let Some(fields) = split_1c_braced_fields(field.trim(), 0) else {
        return;
    };
    if let Some(wrapper) = fields.first().map(|field| field.trim())
        && form_child_item_tag(wrapper, &fields) == Some("Table")
        && let Some(identity) = fields
            .get(1)
            .and_then(|field| split_1c_braced_fields(field.trim(), 0))
        && let Some(table_id) = identity.first().map(|field| field.trim())
        && let Some(group_id) = parse_form_table_property_bag_number(&fields, "16")
        && let Some(group_name) = item_names_by_id.get(&group_id)
    {
        group_names_by_table_id.insert(table_id.to_string(), group_name.clone());
    }
    for nested in fields {
        if nested.trim_start().starts_with('{') {
            collect_form_table_user_settings_groups(
                nested,
                item_names_by_id,
                group_names_by_table_id,
            );
        }
    }
}

fn apply_form_table_user_settings_groups(
    items: &mut [FormChildItem],
    group_names_by_table_id: &BTreeMap<String, String>,
) {
    for item in items {
        if item.tag == "Table"
            && let Some(group_name) = group_names_by_table_id.get(&item.id)
        {
            item.user_settings_group = Some(group_name.clone());
        }
        apply_form_table_user_settings_groups(&mut item.child_items, group_names_by_table_id);
    }
}

fn parse_form_table_update_on_data_change(fields: &[&str]) -> Option<&'static str> {
    let value = form_table_property_bag_value(fields, "14")?;
    let fields = split_1c_braced_fields(value.trim(), 0)?;
    match (
        fields.first().and_then(|field| parse_1c_string(field)),
        fields.get(1).map(|field| field.trim()),
        fields.get(2).map(|field| field.trim()),
    ) {
        (Some(marker), Some(FORM_UPDATE_ON_DATA_CHANGE_UUID), Some("0")) if marker == "#" => {
            Some("Auto")
        }
        _ => None,
    }
}

fn form_table_property_bag_value<'a>(fields: &[&'a str], key: &str) -> Option<&'a str> {
    fields.windows(2).find_map(|window| {
        (window[0].trim() == key && window[1].trim_start().starts_with('{')).then_some(window[1])
    })
}

fn form_child_item_tag(wrapper: &str, fields: &[&str]) -> Option<&'static str> {
    match wrapper {
        "22" => match fields.get(5).map(|value| value.trim())? {
            "0" => Some("CommandBar"),
            "1" => Some("Popup"),
            "2" => Some("ColumnGroup"),
            "3" => Some("Pages"),
            "4" => Some("Page"),
            "5" => Some("UsualGroup"),
            "6" => Some("ButtonGroup"),
            "8" => Some("ContextMenu"),
            "9" => Some("AutoCommandBar"),
            _ => None,
        },
        "12" => match fields.get(5).map(|value| value.trim())? {
            "1" => Some("PictureDecoration"),
            _ => None,
        },
        "34" => Some("Button"),
        "48" => match fields
            .get(5 + form_input_field_top_level_offset(fields))
            .map(|value| value.trim())?
        {
            "1" => Some("LabelField"),
            "2" => Some("InputField"),
            "3" => Some("CheckBoxField"),
            "7" => Some("TextDocumentField"),
            _ => None,
        },
        "6" => match fields.get(5).map(|value| value.trim())? {
            "0" => Some("SearchStringAddition"),
            "1" => Some("ViewStatusAddition"),
            "2" => Some("SearchControlAddition"),
            _ => None,
        },
        "73" => Some("Table"),
        "55" => Some("Table"),
        _ => None,
    }
}

fn parse_form_child_item_name(wrapper: &str, fields: &[&str]) -> Option<String> {
    let indexes: &[usize] = match wrapper {
        "73" | "55" | "34" => &[5],
        "48" => &[6, 7],
        _ => &[6],
    };
    indexes.iter().find_map(|index| {
        parse_1c_quoted_string_with_len(fields.get(*index)?.trim())
            .map(|(value, _)| value)
            .filter(|value| !value.is_empty())
    })
}

fn parse_form_child_item_title(wrapper: &str, fields: &[&str]) -> Vec<(String, String)> {
    let indexes: &[usize] = match wrapper {
        "73" | "55" => &[9],
        "34" => &[6],
        "48" => &[9, 10],
        _ => &[7],
    };
    indexes
        .iter()
        .find_map(|index| {
            let values = fields
                .get(*index)
                .map(|field| parse_form_localized_strings(field))
                .unwrap_or_default();
            (!values.is_empty()).then_some(values)
        })
        .unwrap_or_default()
}

fn parse_form_child_item_tooltip(wrapper: &str, fields: &[&str]) -> Vec<(String, String)> {
    let indexes: &[usize] = match wrapper {
        "22" => &[8],
        _ => &[],
    };
    indexes
        .iter()
        .find_map(|index| {
            let values = fields
                .get(*index)
                .map(|field| parse_form_localized_strings(field))
                .unwrap_or_default();
            (!values.is_empty()).then_some(values)
        })
        .unwrap_or_default()
}

fn parse_form_child_item_extended_tooltip(fields: &[&str]) -> Option<(String, String)> {
    fields.iter().find_map(|field| {
        let nested = split_1c_braced_fields(field.trim(), 0)?;
        if nested.first().map(|value| value.trim()) != Some("12") {
            return None;
        }
        if nested.get(5).map(|value| value.trim()) == Some("1") {
            return None;
        }
        let identity = split_1c_braced_fields(nested.get(1)?.trim(), 0)?;
        let id = identity.first()?.trim();
        if id == "0" {
            return None;
        }
        let name = nested.get(6).and_then(|value| parse_1c_string(value))?;
        (!name.is_empty()).then(|| (name, id.to_string()))
    })
}

fn parse_form_picture_decoration_file_name(fields: &[&str]) -> Option<&'static str> {
    fields.iter().find_map(|field| {
        let payload = extract_base64_payload(field)?;
        let content = decode_base64_mime(payload)?;
        is_form_item_picture_content(&content).then(|| ext_picture_file_name(&content))
    })
}

fn parse_form_child_item_event_fields(fields: &[&str]) -> Vec<FormBodyEvent> {
    let mut events = Vec::new();
    for field in fields {
        let field = field.trim();
        if !field.starts_with('{') {
            continue;
        }
        let Some(nested) = split_1c_braced_fields(field, 0) else {
            continue;
        };
        if let Some(event) = parse_form_child_item_event_record(&nested) {
            events.push(event);
        }
    }
    for window in fields.windows(2) {
        if let Some(event) = parse_form_child_item_event_pair(window[0], window[1]) {
            events.push(event);
        }
    }
    events
}

fn parse_form_child_item_event_record(fields: &[&str]) -> Option<FormBodyEvent> {
    if fields.first().map(|value| value.trim()) != Some("1") {
        return None;
    }
    parse_form_child_item_event_pair(fields.get(1)?, fields.get(2)?)
}

fn parse_form_child_item_event_pair(
    event_field: &str,
    handler_field: &str,
) -> Option<FormBodyEvent> {
    let event = parse_form_child_item_event_identifier(event_field)?;
    let (handler, _) = parse_1c_quoted_string_with_len(handler_field.trim())?;
    let handler = handler.trim();
    if handler.is_empty() || !is_probable_form_event_handler(handler) {
        return None;
    }
    Some(FormBodyEvent {
        name: event,
        handler: handler.to_string(),
    })
}

