        fields[10] = "{1,0}".to_string();
        fields[11] = "{0}".to_string();
        fields[18] = "{1,0}".to_string();
        fields[19] = "{1,0}".to_string();
        fields[41] = "1".to_string();
        fields[42] = format!(
            r#"{{22,{{23,{form_uuid}}},0,0,0,8,"FieldContextMenu",{{1,0}},{{1,0}},0,1,0}}"#
        );
        let field = format!("{{{}}}", fields.join(","));

