    #[test]
    fn extracts_settings_storage_xml_with_manager_generated_type() {
        let uuid = "44444444-aaaa-4aaa-8aaa-aaaaaaaaaaaa";
        let manager_type_id = "44444444-bbbb-4bbb-8bbb-bbbbbbbbbbbb";
        let manager_value_id = "44444444-cccc-4ccc-8ccc-cccccccccccc";
        let plain = format!(
            "{{1,\r\n{{2,\r\n{{0,\r\n{{3,\r\n{{1,0,{uuid}}},\"UserSettings\",{{1,\"en\",\"User settings\"}},\"\",0,0,00000000-0000-0000-0000-000000000000,0}}\r\n}},{manager_type_id},{manager_value_id},00000000-0000-0000-0000-000000000000,00000000-0000-0000-0000-000000000000,00000000-0000-0000-0000-000000000000,00000000-0000-0000-0000-000000000000}},2,\r\n{{0}},\r\n{{0}}\r\n}},0}}"
        );
        let blob = deflate_for_test(plain.as_bytes());

        let extracted = extract_metadata_source_xml(
            &blob,
            uuid,
            &BTreeMap::new(),
            &BTreeMap::new(),
            &BTreeMap::new(),
        )
        .unwrap();
        let properties = parse_simple_metadata_xml_properties(&extracted.xml).unwrap();
        let repacked = pack_simple_metadata_blob_from_xml(&blob, &extracted.xml).unwrap();
        let generated_types = parse_generated_type_entries_from_blob(&blob, uuid).unwrap();
        let xml = String::from_utf8(extracted.xml.clone()).unwrap();

        assert_eq!(
            extracted.relative_path,
            PathBuf::from("SettingsStorages").join("UserSettings.xml")
        );
        assert_eq!(properties.kind, "SettingsStorage");
        assert_eq!(properties.uuid, uuid);
        assert!(xml.contains(
            r#"<xr:GeneratedType name="SettingsStorageManager.UserSettings" category="Manager">"#
        ));
        assert!(xml.contains(&format!("<xr:TypeId>{manager_type_id}</xr:TypeId>")));
        assert!(xml.contains(&format!("<xr:ValueId>{manager_value_id}</xr:ValueId>")));
        assert!(generated_types.contains(&(
            manager_type_id.to_string(),
            "cfg:SettingsStorageManager.UserSettings".to_string()
        )));
        assert!(!repacked.blob.is_empty());
        let repacked_plain =
            String::from_utf8(inflate_raw_deflate(&repacked.blob).unwrap()).unwrap();
        assert_eq!(repacked_plain, plain);

        let extracted_v21 = extract_metadata_source_xml_with_refs(
            &blob,
            uuid,
            &BTreeMap::new(),
            &BTreeMap::new(),
            &BTreeMap::new(),
            &BTreeMap::new(),
            &BTreeMap::new(),
            &BTreeMap::new(),
            InfobaseConfigSourceVersion::V2_21,
        )
        .unwrap();
        let xml_v21 = String::from_utf8(extracted_v21.xml).unwrap();
        assert!(xml_v21.contains(r#"version="2.21""#));
        assert!(!xml_v21.contains(r#"version="2.20""#));
        assert!(xml_v21.contains("SettingsStorageManager.UserSettings"));
    }

    #[test]
    fn extracts_additional_simple_service_metadata_xml_from_blobs() {
        let language_uuid = "11111111-aaaa-4aaa-8aaa-aaaaaaaaaaaa";
        let language_blob = deflate_for_test(
            format!(
                "{{1,\r\n{{0,\r\n{{3,\r\n{{1,0,{language_uuid}}},\"English\",{{1,\"en\",\"English\"}},\"\",0,0,00000000-0000-0000-0000-000000000000,0}},\"en\"}},0}}"
            )
            .as_bytes(),
        );
        let xdto_uuid = "22222222-aaaa-4aaa-8aaa-aaaaaaaaaaaa";
        let xdto_blob = deflate_for_test(
            format!(
                "{{1,\r\n{{1,\r\n{{3,\r\n{{1,0,{xdto_uuid}}},\"Exchange\",{{1,\"en\",\"Exchange\"}},\"\",0,0,00000000-0000-0000-0000-000000000000,0}},\"http://example.com/exchange\"}},0}}"
            )
            .as_bytes(),
        );
        let http_uuid = "33333333-aaaa-4aaa-8aaa-aaaaaaaaaaaa";
        let url_template_uuid = "33333333-bbbb-4bbb-8bbb-bbbbbbbbbbbb";
        let method_uuid = "33333333-cccc-4ccc-8ccc-cccccccccccc";
        let http_blob = deflate_for_test(
            format!(
                "{{1,\r\n{{2,\"api\",\r\n{{3,\r\n{{1,0,{http_uuid}}},\"Api\",{{1,\"en\",\"API\"}},\"\",0,0,00000000-0000-0000-0000-000000000000,0}},2,20,\r\n{{0,1,\r\n{{7,\r\n{{3,\r\n{{1,0,{url_template_uuid}}},\"Any\",{{1,\"en\",\"Any\"}},\"\",0,0,00000000-0000-0000-0000-000000000000,0}},\"/*\",\r\n{{0,1,\r\n{{8,\r\n{{3,\r\n{{1,0,{method_uuid}}},\"Post\",{{1,\"en\",\"Post\"}},\"\",0,0,00000000-0000-0000-0000-000000000000,0}},\"POST\",\"HandlePost\"}}\r\n}}\r\n}}\r\n}}\r\n}},0}}"
            )
            .as_bytes(),
        );
        let storage_uuid = "44444444-aaaa-4aaa-8aaa-aaaaaaaaaaaa";
        let storage_blob = deflate_for_test(
            format!(
                "{{1,\r\n{{2,\r\n{{0,\r\n{{3,\r\n{{1,0,{storage_uuid}}},\"UserSettings\",{{1,\"en\",\"User settings\"}},\"\",0,0,00000000-0000-0000-0000-000000000000,0}}\r\n}},aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa,bbbbbbbb-bbbb-4bbb-8bbb-bbbbbbbbbbbb,00000000-0000-0000-0000-000000000000,00000000-0000-0000-0000-000000000000,00000000-0000-0000-0000-000000000000,00000000-0000-0000-0000-000000000000}},2,\r\n{{0}},\r\n{{0}}\r\n}},0}}"
            )
            .as_bytes(),
        );
        let job_uuid = "55555555-aaaa-4aaa-8aaa-aaaaaaaaaaaa";
        let job_blob = deflate_for_test(
            format!(
                "{{1,\r\n{{2,\r\n{{3,\r\n{{1,0,{job_uuid}}},\"LoadRates\",{{1,\"en\",\"Load rates\"}},\"\",0,0,00000000-0000-0000-0000-000000000000,0}},\"\",\"Load rates\",1,1,aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa,\"LoadRates\",3,10}},0}}"
            )
            .as_bytes(),
        );

        for (blob, uuid, expected_kind, expected_path) in [
            (
                &language_blob,
                language_uuid,
                "Language",
                PathBuf::from("Languages").join("English.xml"),
            ),
            (
                &xdto_blob,
                xdto_uuid,
                "XDTOPackage",
                PathBuf::from("XDTOPackages").join("Exchange.xml"),
            ),
            (
                &http_blob,
                http_uuid,
                "HTTPService",
                PathBuf::from("HTTPServices").join("Api.xml"),
            ),
            (
                &storage_blob,
                storage_uuid,
                "SettingsStorage",
                PathBuf::from("SettingsStorages").join("UserSettings.xml"),
            ),
            (
                &job_blob,
                job_uuid,
                "ScheduledJob",
                PathBuf::from("ScheduledJobs").join("LoadRates.xml"),
            ),
        ] {
            let extracted = extract_metadata_source_xml(
                blob,
                uuid,
                &BTreeMap::new(),
                &BTreeMap::new(),
                &BTreeMap::new(),
            )
            .unwrap();
            let properties = parse_simple_metadata_xml_properties(&extracted.xml).unwrap();
            let repacked = pack_simple_metadata_blob_from_xml(blob, &extracted.xml).unwrap();

            assert_eq!(extracted.relative_path, expected_path);
            assert_eq!(properties.kind, expected_kind);
            assert_eq!(properties.uuid, uuid);
            if expected_kind == "XDTOPackage" {
                let xml = String::from_utf8(extracted.xml.clone()).unwrap();
                assert!(xml.contains("<Namespace>http://example.com/exchange</Namespace>"));
                assert!(xml.contains(r#"version="2.20""#));
                let extracted_v21 = extract_metadata_source_xml_with_refs(
                    blob,
                    uuid,
                    &BTreeMap::new(),
                    &BTreeMap::new(),
                    &BTreeMap::new(),
                    &BTreeMap::new(),
                    &BTreeMap::new(),
                    &BTreeMap::new(),
                    InfobaseConfigSourceVersion::V2_21,
                )
                .unwrap();
                let xml_v21 = String::from_utf8(extracted_v21.xml).unwrap();
                assert!(xml_v21.contains("<Namespace>http://example.com/exchange</Namespace>"));
                assert!(xml_v21.contains(r#"version="2.21""#));
                assert!(!xml_v21.contains(r#"version="2.20""#));
            }
            if expected_kind == "HTTPService" {
                let xml = String::from_utf8(extracted.xml.clone()).unwrap();
                assert!(xml.contains("<RootURL>api</RootURL>"));
                assert!(xml.contains("<ReuseSessions>AutoUse</ReuseSessions>"));
                assert!(xml.contains("<SessionMaxAge>20</SessionMaxAge>"));
                assert!(xml.contains(&format!(r#"<URLTemplate uuid="{url_template_uuid}">"#)));
                assert!(xml.contains("<Template>/*</Template>"));
                assert!(xml.contains(&format!(r#"<Method uuid="{method_uuid}">"#)));
                assert!(xml.contains("<HTTPMethod>POST</HTTPMethod>"));
                assert!(xml.contains("<Handler>HandlePost</Handler>"));

                let extracted_v21 = extract_metadata_source_xml_with_refs(
                    blob,
                    uuid,
                    &BTreeMap::new(),
                    &BTreeMap::new(),
                    &BTreeMap::new(),
                    &BTreeMap::new(),
                    &BTreeMap::new(),
                    &BTreeMap::new(),
                    InfobaseConfigSourceVersion::V2_21,
                )
                .unwrap();
                let xml_v21 = String::from_utf8(extracted_v21.xml).unwrap();
                assert!(xml_v21.contains("<RootURL>api</RootURL>"));
                assert!(xml_v21.contains(r#"version="2.21""#));
                assert!(!xml_v21.contains(r#"version="2.20""#));
            }
            assert!(!repacked.blob.is_empty());
        }
    }

    #[test]
    fn extracts_filter_criterion_xml_with_standard_commands() {
        let uuid = "55555555-bbbb-4bbb-8bbb-bbbbbbbbbbbb";
        let plain = format!(
            "{{1,\r\n{{14,\r\n{{3,\r\n{{1,0,{uuid}}},\"ImportantFilters\",{{1,\"en\",\"Important filters\"}},\"\",0,0,00000000-0000-0000-0000-000000000000,0}},0}},0}}"
        );
        let blob = deflate_for_test(plain.as_bytes());

        let extracted = extract_metadata_source_xml(
            &blob,
            uuid,
            &BTreeMap::new(),
            &BTreeMap::new(),
            &BTreeMap::new(),
        )
        .unwrap();
        let properties = parse_simple_metadata_xml_properties(&extracted.xml).unwrap();
        let repacked = pack_simple_metadata_blob_from_xml(&blob, &extracted.xml).unwrap();
        let repacked_plain =
            String::from_utf8(inflate_raw_deflate(&repacked.blob).unwrap()).unwrap();
        let xml = String::from_utf8(extracted.xml).unwrap();

        assert_eq!(
            extracted.relative_path,
            PathBuf::from("FilterCriteria").join("ImportantFilters.xml")
        );
        assert_eq!(properties.kind, "FilterCriterion");
        assert_eq!(properties.uuid, uuid);
        assert!(xml.contains(r#"version="2.20""#));
        assert!(xml.contains("<UseStandardCommands>true</UseStandardCommands>"));
        assert_eq!(repacked_plain, plain);

        let extracted_v21 = extract_metadata_source_xml_with_refs(
            &blob,
            uuid,
            &BTreeMap::new(),
            &BTreeMap::new(),
            &BTreeMap::new(),
            &BTreeMap::new(),
            &BTreeMap::new(),
            &BTreeMap::new(),
            InfobaseConfigSourceVersion::V2_21,
        )
        .unwrap();
        let xml_v21 = String::from_utf8(extracted_v21.xml).unwrap();
        assert!(xml_v21.contains(r#"version="2.21""#));
        assert!(!xml_v21.contains(r#"version="2.20""#));
        assert!(xml_v21.contains("<UseStandardCommands>true</UseStandardCommands>"));
    }

    #[test]
    fn extracts_sfc_metadata_family_xml_from_blob_shapes() {
        let cases = vec![
            (
                "66666666-aaaa-4aaa-8aaa-aaaaaaaaaaaa",
                deflate_for_test(
                    b"{1,\r\n{0,\r\n{3,\r\n{1,0,66666666-aaaa-4aaa-8aaa-aaaaaaaaaaaa},\"MessageExchange\",{1,\"en\",\"Message exchange\"},\"\",0,0,00000000-0000-0000-0000-000000000000,0},11111111-1111-4111-8111-111111111111,22222222-2222-4222-8222-222222222222,\"\"},0}",
                ),
                "IntegrationService",
                PathBuf::from("IntegrationServices").join("MessageExchange.xml"),
            ),
            (
                "77777777-aaaa-4aaa-8aaa-aaaaaaaaaaaa",
                deflate_for_test(
                    b"{1,\r\n{1,\r\n{3,\r\n{1,0,77777777-aaaa-4aaa-8aaa-aaaaaaaaaaaa},\"NotifyUsers\",{1,\"en\",\"Notify users\"},\"\",0,0,00000000-0000-0000-0000-000000000000,0},0,{4,0,{0},\"\",-1,-1,1,0,\"\"}},0}",
                ),
                "Bot",
                PathBuf::from("Bots").join("NotifyUsers.xml"),
            ),
            (
                "88888888-aaaa-4aaa-8aaa-aaaaaaaaaaaa",
                deflate_for_test(
                    b"{1,\r\n{2,\r\n{\"https://example.invalid/ws?wsdl\",0},\r\n{3,\r\n{1,0,88888888-aaaa-4aaa-8aaa-aaaaaaaaaaaa},\"UpdateFiles\",{1,\"en\",\"Update files\"},\"\",0,0,00000000-0000-0000-0000-000000000000,0},11111111-1111-4111-8111-111111111111,22222222-2222-4222-8222-222222222222},0}",
                ),
                "WSReference",
                PathBuf::from("WSReferences").join("UpdateFiles.xml"),
            ),
            (
                "99999999-aaaa-4aaa-8aaa-aaaaaaaaaaaa",
                deflate_for_test(
                    b"{1,\r\n{3,\r\n{3,\r\n{1,0,99999999-aaaa-4aaa-8aaa-aaaaaaaaaaaa},\"Main\",{1,\"en\",\"Main\"},\"\",0,0,00000000-0000-0000-0000-000000000000,0}\r\n},0}",
                ),
                "Style",
                PathBuf::from("Styles").join("Main.xml"),
            ),
            (
                "aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa",
                deflate_for_test(
                    b"{1,\r\n{3,\r\n{3,\r\n{1,0,aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa},\"CashDocuments\",{1,\"en\",\"Cash documents\"},\"\",0,0,00000000-0000-0000-0000-000000000000,0},1,11,1,1,0},0}",
                ),
                "DocumentNumerator",
                PathBuf::from("DocumentNumerators").join("CashDocuments.xml"),
            ),
            (
                "bbbbbbbb-bbbb-4bbb-8bbb-bbbbbbbbbbbb",
                deflate_for_test(
                    b"{1,\r\n{6,11111111-1111-4111-8111-111111111111,22222222-2222-4222-8222-222222222222,\r\n{0,\r\n{3,\r\n{1,0,bbbbbbbb-bbbb-4bbb-8bbb-bbbbbbbbbbbb},\"CompanyDocuments\",{1,\"en\",\"Company documents\"},\"\",0,0,00000000-0000-0000-0000-000000000000,0}\r\n},{0}},0}",
                ),
                "Sequence",
                PathBuf::from("Sequences").join("CompanyDocuments.xml"),
            ),
        ];

        for (uuid, blob, expected_kind, expected_path) in cases {
            let extracted = extract_metadata_source_xml(
                &blob,
                uuid,
                &BTreeMap::new(),
                &BTreeMap::new(),
                &BTreeMap::new(),
            )
            .unwrap();
            let properties = parse_simple_metadata_xml_properties(&extracted.xml).unwrap();

            assert_eq!(extracted.relative_path, expected_path);
            assert_eq!(properties.kind, expected_kind);
            assert_eq!(properties.uuid, uuid);
        }
    }

    #[test]
    fn selected_export_skips_broad_indexes_only_for_self_contained_metadata() {
        let self_contained = vec![MetadataTextRow {
            file_name: "aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa".to_string(),
            text: String::new(),
            object_code: Some(3),
            header: None,
            kind: Some("DocumentNumerator".to_string()),
            folder: Some("DocumentNumerators"),
        }];
        let referencing = vec![MetadataTextRow {
            file_name: "bbbbbbbb-bbbb-4bbb-8bbb-bbbbbbbbbbbb".to_string(),
            text: String::new(),
            object_code: Some(2),
            header: None,
            kind: Some("FunctionalOption".to_string()),
            folder: Some("FunctionalOptions"),
        }];
        let ws_reference = vec![MetadataTextRow {
            file_name: "cccccccc-cccc-4ccc-8ccc-cccccccccccc".to_string(),
            text: String::new(),
            object_code: Some(2),
            header: None,
            kind: Some("WSReference".to_string()),
            folder: Some("WSReferences"),
        }];
        let integration_service = vec![MetadataTextRow {
            file_name: "dddddddd-dddd-4ddd-8ddd-dddddddddddd".to_string(),
            text: String::new(),
            object_code: Some(0),
            header: None,
            kind: Some("IntegrationService".to_string()),
            folder: Some("IntegrationServices"),
        }];

        assert!(!selected_export_needs_broad_metadata_indexes(
            false,
            &BTreeSet::from(["aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa".to_string()]),
            &self_contained,
        ));
        assert!(selected_export_needs_broad_metadata_indexes(
            false,
            &BTreeSet::from(["bbbbbbbb-bbbb-4bbb-8bbb-bbbbbbbbbbbb".to_string()]),
            &referencing,
        ));
        assert!(selected_export_needs_broad_metadata_indexes(
            false,
            &BTreeSet::from(["aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa.0".to_string()]),
            &self_contained,
        ));
        assert!(!selected_export_needs_broad_metadata_indexes(
            false,
            &BTreeSet::from([
                "cccccccc-cccc-4ccc-8ccc-cccccccccccc".to_string(),
                "cccccccc-cccc-4ccc-8ccc-cccccccccccc.0".to_string(),
            ]),
            &ws_reference,
        ));
        assert!(selected_export_needs_broad_metadata_indexes(
            false,
            &BTreeSet::from(["cccccccc-cccc-4ccc-8ccc-cccccccccccc.0".to_string()]),
            &[],
        ));
        assert!(!selected_export_needs_broad_metadata_indexes(
            true,
            &BTreeSet::from([
                "dddddddd-dddd-4ddd-8ddd-dddddddddddd".to_string(),
                "dddddddd-dddd-4ddd-8ddd-dddddddddddd.0".to_string(),
            ]),
            &integration_service,
        ));
        assert!(selected_export_needs_broad_metadata_indexes(
            false,
            &BTreeSet::from(["dddddddd-dddd-4ddd-8ddd-dddddddddddd.0".to_string()]),
            &integration_service,
        ));
    }

    #[test]
    fn selected_configuration_source_assets_request_only_required_indexes() {
        let client_only = selected_configuration_source_asset_index_needs(&BTreeSet::from([
            "aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa.b".to_string(),
        ]))
        .expect("configuration client interface selection");
        assert!(!client_only.needs_broad_metadata());

        let versions_only = selected_configuration_source_asset_index_needs(&BTreeSet::from([
            "versions".to_string(),
        ]))
        .expect("versions selection");
        assert!(!versions_only.needs_broad_metadata());
        assert!(!versions_only.metadata_refs);

        let home_page = selected_configuration_source_asset_index_needs(&BTreeSet::from([
            "aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa.8".to_string(),
        ]))
        .expect("configuration home page selection");
        assert!(home_page.form_refs);
        assert!(!home_page.command_refs);
        assert!(!home_page.object_refs);

        let command_interface = selected_configuration_source_asset_index_needs(&BTreeSet::from([
            "aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa.9".to_string(),
            "aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa.a".to_string(),
        ]))
        .expect("configuration command interface selection");
        assert!(command_interface.command_refs);
        assert!(command_interface.metadata_refs);
        assert!(!command_interface.form_refs);
        assert!(!command_interface.type_index);

        let subsystems_order = selected_configuration_source_asset_index_needs(&BTreeSet::from([
            "aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa.a".to_string(),
        ]))
        .expect("configuration subsystems order selection");
        assert!(subsystems_order.metadata_refs);
        assert!(!subsystems_order.command_refs);
        assert!(!subsystems_order.needs_broad_metadata());

        assert!(
            selected_configuration_source_asset_index_needs(&BTreeSet::from([
                "aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa.f".to_string(),
            ]))
            .is_none()
        );
    }

    #[test]
    fn command_interface_reference_index_preserves_row_order_overwrites() {
        let uuid = "aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa";
        let old_row = MetadataTextRow {
            file_name: uuid.to_string(),
            text: String::new(),
            object_code: Some(9),
            header: Some(MetadataHeader {
                uuid: uuid.to_string(),
                name: "OpenOld".to_string(),
                synonyms: Vec::new(),
                comment: String::new(),
                template_type_code: None,
            }),
            kind: Some("CommonCommand".to_string()),
            folder: Some("CommonCommands"),
        };
        let new_row = MetadataTextRow {
            file_name: uuid.to_string(),
            text: String::new(),
            object_code: Some(9),
            header: Some(MetadataHeader {
                uuid: uuid.to_string(),
                name: "OpenNew".to_string(),
                synonyms: Vec::new(),
                comment: String::new(),
                template_type_code: None,
            }),
            kind: Some("CommonCommand".to_string()),
            folder: Some("CommonCommands"),
        };

        let index = build_command_interface_reference_index_from_texts(&[old_row, new_row]);

        assert_eq!(
            index.get(uuid).map(String::as_str),
            Some("CommonCommand.OpenNew")
        );
    }

    #[test]
    fn selected_command_interface_refs_collect_command_fields_only() {
        let command_uuid = "aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa";
        let group_uuid = "1af6d528-0b86-4fba-ab95-bd7475db03ba";
        let body = deflate_for_test(
            format!(
                "{{7,1,1,{{0,{command_uuid}}},{{0,{{0,{{\"B\",1}},0}}}},1,1,{{0,{command_uuid}}},{group_uuid},1,1,1,{group_uuid},{{0,{command_uuid}}},0,1,1,{group_uuid},0}}"
            )
            .as_bytes(),
        );

        let refs = command_interface_command_refs_from_blob(&body).unwrap();

        assert_eq!(refs.len(), 1);
        assert!(refs.contains(&CommandInterfaceCommandReference {
            code: "0".to_string(),
            uuid: command_uuid.to_string(),
        }));
        assert!(!refs.iter().any(|reference| reference.uuid == group_uuid));
    }

